    // Ensure a price was provided.
    if ( !empty( $price ) ) {

        // Remove unwanted characters from price.
        $price = preg_replace("/[^0-9,.]/", "", $price);

        // Remove unwanted characters from min price.
        $map = preg_replace("/[^0-9,.]/", "", $map);

        // Remove unwanted characters from max price.
