function exclude_products_from_gmc_export( $articles, $options, $export_id ) {

    // Target GMC exports only
    if ( $options['xml_template_type'] !== 'XmlGoogleMerchants' ) {
        return $articles;
    }

    // Iterate through exported products
    foreach ( $articles as $key => $article ) {

        if ( ! empty( $article['id'] ) ) {
            $post_id = $article['id'];
            $parent_id = wp_get_post_parent_id( $post_id );

            // Check for draft status (both product and parent)
            if ( get_post_status( $post_id ) === 'draft' || 
                 ( $parent_id && get_post_status( $parent_id ) === 'draft' ) ) {

                unset( $articles[ $key ] ); 
            }
        }
    }

    // Ensure proper array return 
    return ! empty( $articles ) ? $articles : []; 
}
