function find_url( $string ) {
    // Find the URL.
    preg_match_all('#\bhttps?://[^\s()<>]+(?:\([\w\d]+\)|([^[:punct:]\s]|/))#', $string, $match);
    // Return the first found URL.
    return  $match[0][0];
}
