function soflyy_extract_path($ftppath) {
    $parts = explode('/', $ftppath);
    // Change 'img' with your desired path part
    $index = array_search('img', $parts);

    if ($index !== false) {
        $path = implode('/', array_slice($parts, $index + 1));
        return $path;
    }

    return '';
}
```

