function my_export_seo( $id, $field = '', $taxonomy = '' ) {
	if ( empty( $field ) ) return;

	$seo_data = get_option( 'wpseo_taxonomy_meta' );
	if ( empty( $seo_data ) ) return;

	$seo_data = maybe_unserialize( $seo_data );

	if ( ! array_key_exists( $taxonomy, $seo_data ) ) return;

	if ( array_key_exists( $id, $seo_data[ $taxonomy ] ) ) {
		return $seo_data[ $taxonomy ][ $id ][ $field ];
	}
}
